  1229	pub fn extract_env_from_config_path(path: &Path) -> Option<String> {
  1230	    let filename = path
  1231	        .file_name()
  1232	        .and_then(|n| n.to_str())
  1233	        .unwrap_or_default();
  1234	
  1235	    // Pattern matches:
  1236	    // - mise.{env}.toml -> captures env
  1237	    // - mise.{env}.local.toml -> captures env (env-specific local config)
  1238	    // - .mise.{env}.toml -> captures env
  1239	    // - config.{env}.toml -> captures env
  1240	    // Does NOT match (returns None):
  1241	    // - mise.toml, .mise.toml, config.toml (base configs)
  1242	    // - mise.local.toml (local without env - filtered by "local" check)
  1243	    let re = regex!(r"^(?:\.?mise|config)\.([^.]+)(?:\.local)?\.toml$");
