    52	        toml::Value::Integer(i) => Value::from(i),
    53	        toml::Value::Float(f) => Value::from(f),
    54	        toml::Value::Boolean(b) => Value::from(b),
    55	        toml::Value::Datetime(dt) => {
    56	            // Parse the datetime string back into a toml_edit datetime
    57	            dt.to_string()
    58	                .parse::<toml_edit::Datetime>()
