        match source {
            PluginSource::Git {
                url,
                git_ref,
                subdir,
            } => {
                assert_eq!(url, "https://github.com/user/plugin.git");
                assert_eq!(git_ref, Some("v1.0.0".to_string()));
                assert_eq!(subdir, None);
            }
            _ => panic!("Expected a git plugin"),
        }
